7	public final class GenericType: NSObject, SourceryModelWithoutDescription, Diffable {
8	    /// The name of the base type, i.e. `Array` for `Array<Int>`
9	    public var name: String
10	
11	    /// This generic type parameters
12	    public let typeParameters: [GenericTypeParameter]
13	
14	    /// :nodoc:
15	    public init(name: String, typeParameters: [GenericTypeParameter] = []) {
16	        self.name = name
17	        self.typeParameters = typeParameters
18	    }
19	
20	    public var asSource: String {
21	        let arguments = typeParameters
22	          .map({ $0.typeName.asSource })
23	          .joined(separator: ", ")
24	        return "\(name)<\(arguments)>"
25	    }
26	
27	    public override var description: String {
28	        asSource
29	    }
30	
31	    public func diffAgainst(_ object: Any?) -> DiffableResult {
32	        let results = DiffableResult()
33	        guard let castObject = object as? GenericType else {
34	            results.append("Incorrect type <expected: GenericType, received: \(Swift.type(of: object))>")
35	            return results
36	        }
37	        results.append(contentsOf: DiffableResult(identifier: "name").trackDifference(actual: self.name, expected: castObject.name))
38	        results.append(contentsOf: DiffableResult(identifier: "typeParameters").trackDifference(actual: self.typeParameters, expected: castObject.typeParameters))
39	        return results
40	    }
41	
42	    /// :nodoc:
43	    // sourcery: skipJSExport
44	    public override var hash: Int {
45	        var hasher = Hasher()
46	        hasher.combine(self.name)
47	        hasher.combine(self.typeParameters)
48	        return hasher.finalize()
49	    }
50	
51	    /// :nodoc:
52	    public override func isEqual(_ object: Any?) -> Bool {
53	        guard let rhs = object as? GenericType else { return false }
54	        if self.name != rhs.name { return false }
55	        if self.typeParameters != rhs.typeParameters { return false }
56	        return true
57	    }   
