22	    override func spec() {
23	        describe("ParserComposer") {
24	            describe("uniqueTypesAndFunctions") {
25	                func parse(_ code: String) -> [Type] {
26	                    guard let parserResult = try? makeParser(for: code).parse() else { fail(); return [] }
27	                    return Composer.uniqueTypesAndFunctions(parserResult).types
28	                }
29	
30	                func parseFunctions(_ code: String) -> [SourceryMethod] {
31	                    guard let parserResult = try? makeParser(for: code).parse() else { fail(); return [] }
32	                    return Composer.uniqueTypesAndFunctions(parserResult).functions
33	                }
34	
35	                func parseModules(_ modules: (name: String?, contents: String)...) -> (types: [Type], functions: [SourceryMethod], typealiases: [Typealias]) {
36	                    let moduleResults = modules.compactMap {
37	                        try? makeParser(for: $0.contents, module: $0.name).parse()
38	                    }
39	
40	                    let parserResult = moduleResults.reduce(FileParserResult(path: nil, module: nil, types: [], functions: [], typealiases: [])) { acc, next in
41	                        acc.typealiases += next.typealiases
42	                        acc.types += next.types
43	                        acc.functions += next.functions
44	                        return acc
45	                    }
46	
47	                    return Composer.uniqueTypesAndFunctions(parserResult)
48	                }
49	
50	                context("given class hierarchy") {
51	                    var fooType: Type!
52	                    var barType: Type!
53	                    var bazType: Type!
54	
55	                    beforeEach {
56	                        let input =
57	                            """
58	                            class Foo {
59	                                var foo: Int;
60	                                func fooMethod() {}
61	                            }
62	                            class Bar: Foo {
63	                                var bar: Int
64	                            }
65	                            class Baz: Bar {
66	                                var baz: Int;
67	                                func bazMethod() {}
68	                            }
69	                            """
70	                        let parsedResult = parse(input)
71	                        fooType = parsedResult[2]
72	                        barType = parsedResult[0]
73	                        bazType = parsedResult[1]
74	                    }
75	
76	                    it("resolves methods definedInType") {
77	                        expect(fooType.allMethods.first?.definedInType).to(equal(fooType))
78	                        expect(barType.allMethods.first?.definedInType).to(equal(fooType))
79	                        expect(bazType.allMethods.first?.definedInType).to(equal(bazType))
80	                        expect(bazType.allMethods.last?.definedInType).to(equal(fooType))
81	                    }
82	
83	                    it("resolves variables definedInType") {
84	                        expect(fooType.allVariables.first?.definedInType).to(equal(fooType))
85	                        expect(barType.allVariables[0].definedInType).to(equal(barType))
86	                        expect(barType.allVariables[1].definedInType).to(equal(fooType))
87	                        expect(bazType.allVariables[0].definedInType).to(equal(bazType))
88	                        expect(bazType.allVariables[1].definedInType).to(equal(barType))
89	                        expect(bazType.allVariables[2].definedInType).to(equal(fooType))
90	                    }
91	
92	                    context("given method with return type") {
93	                        it("finds actual return type") {
94	                            let types = parse("class Foo { func foo() -> Bar { } }; class Bar {}")
95	                            let method = types.last?.methods.first
96	
97	                            expect(method?.returnType)
98	                              .to(equal(Class(name: "Bar")))
99	                        }
100	                    }

