5	extension Attribute {
6	    convenience init(_ attribute: AttributeSyntax) {
7	        var arguments = [String: NSObject]()
8	        attribute.arguments?.description
9	          .split(separator: ",")
10	          .enumerated()
11	          .forEach { (idx, part) in
12	              let components = part.split(separator: ":", maxSplits: 1)
13	              switch components.count {
14	              case 2:
15	                  arguments[components[0].trimmed] = components[1].trimmed as NSString
16	              case 1:
17	                  arguments["\(idx)"] = components[0].trimmed as NSString
18	              default:
19	                  Log.astError("Unrecognized attribute format \(attribute.arguments?.description ?? "")")
20	                  return
21	              }
22	          }
23	
24	        self.init(name: attribute.attributeName.description.trimmed, arguments: arguments,  description: attribute.withoutTrivia().description.trimmed)
25	    }
26	
27	    static func from(_ attributes: AttributeListSyntax?) -> AttributeList {
28	        let array = attributes?
29	          .compactMap { syntax -> Attribute? in
30	            if let syntax = syntax.as(AttributeSyntax.self) {
31	                return Attribute(syntax)
32	            } else {
33	                return nil
34	            }
35	          } ?? []
36	
37	        var final = AttributeList()
38	        array.forEach { attribute in
39	            var attributes = final[attribute.name, default: []]
40	            attributes.append(attribute)
41	            final[attribute.name] = attributes
42	        }
43	
44	        return final
45	    }
46	}
