48	private extension TokenKind {
49	    var isIdentifier: Bool {
50	        switch self {
51	        case .identifier:
52	            return true
53	        default:
54	            return false
55	        }
56	    }
57	
58	    var isComma: Bool {
59	        switch self {
60	        case .comma:
61	            return true
62	        default:
63	            return false
64	        }
65	    }
66	}
