68	private extension LabeledExprSyntax {
69	    /// Returns key and value strings for a tuple element. If the tuple does not have an argument label,
70	    /// `nil` will be returned for the key.
71	    var keyAndValue: (key: String?, value: String) {
72	        var iterator = tokens(viewMode: .fixedUp).makeIterator()
73	        if let argumentLabelToken = iterator.next(),
74	           let colonToken = iterator.next(),
75	           case let .identifier(argumentLabel) = argumentLabelToken.tokenKind,
76	           colonToken.tokenKind == .colon {
77	            // This argument has a label
78	            let valueText = getConcatenatedTokenText(iterator: &iterator)
79	            return (argumentLabel.trimmed, valueText)
80	        } else {
81	            // This argument does not have a label
82	            iterator = tokens(viewMode: .fixedUp).makeIterator()
83	            let valueText = getConcatenatedTokenText(iterator: &iterator)
84	            return (nil, valueText)
85	        }
86	    }
87	
88	    private func getConcatenatedTokenText(iterator: inout TokenSequence.Iterator) -> String {
89	        var valueText = ""
90	        var lastTokenWasComma = false
91	        while let nextToken = iterator.next() {
92	            lastTokenWasComma = nextToken.tokenKind.isComma
93	            valueText += nextToken.text.trimmed
94	        }
95	
96	        valueText = valueText.replacingOccurrences(of: "\"", with: "").trimmed
97	        if lastTokenWasComma && valueText.hasSuffix(",") {
98	            valueText.remove(at: valueText.index(before: valueText.endIndex))
99	        }
100	        return valueText

