4	
5	public protocol FileParserType {
6	
7	    var path: String? { get }
8	    var modifiedDate: Date? { get }
9	
10	    /// Creates parser for a given contents and path.
11	    /// - Throws: parsing errors.
12	    init(contents: String, forceParse: [String], parseDocumentation: Bool, path: Path?, module: String?) throws
13	
14	    /// Parses given file context.
15	    ///
16	    /// - Returns: All types we could find.
17	    func parse() throws -> FileParserResult
18	}
