20	public enum ParserEngine {
21	    case swiftSyntax
22	}
23	
24	public var parserEngine: ParserEngine = .swiftSyntax
25	
26	public func makeParser(for contents: String, forceParse: [String] = [], parseDocumentation: Bool = false, path: Path? = nil, module: String? = nil) throws -> FileParserType {
27	    switch parserEngine {
28	    case .swiftSyntax:
29	        return try FileParserSyntax(contents: contents, forceParse: forceParse, parseDocumentation: parseDocumentation, path: path, module: module)
30	    }
31	}
