1	import Foundation
2	import SourceryRuntime
3	
4	extension String {
5	    private static let optionalTypeName: TypeName = {
6	        let t = TypeName(name: "Optional", isOptional: true)
7	        t.name = "Optional"
8	        return t
9	    }()
10	    
11	    /// infers type or return self as type if it's a single word
12	    private var inferElementType: TypeName? {
13	        if let inferred = inferType {
14	            return inferred
15	        }
16	        
17	        let trimmed = self.trimmed
18	        if trimmed.rangeOfCharacter(from: .whitespacesAndNewlines) == nil {
19	            return TypeName(trimmed)
20	        }
21	        
22	        return nil
23	    }
24	    
25	    /// Infers type from input string
26	    internal var inferType: TypeName? {
27	        let string = self
28	            .trimmingCharacters(in: .whitespacesAndNewlines)
29	            .strippingComments()
30	            .trimmingCharacters(in: .whitespacesAndNewlines)
31	        
32	        // probably lazy property or default value with closure,
33	        // we expect explicit type, as we don't know return type
34	        guard !(string.hasPrefix("{") && string.hasSuffix(")")) else {
35	            let body = String(string.dropFirst())
36	            guard !body.contains("return") else {
37	                return nil
38	            }
39	            
40	            // if there is no return statement it means the return value is the first expression
41	            let components = body.components(separatedBy: "(", excludingDelimiterBetween: ("<[(", ")]>"))
42	            if let first = components.first {
43	                return (first + "()").inferType
44	            }
45	            return nil
46	        }
47	        
48	        var inferredType: String
49	        if string == "nil" {
50	            // TODO: add generic
51	            return Self.optionalTypeName
52	        } else if string.first == "\"" {
53	            return TypeName(name: "String")
54	        } else if Bool(string) != nil {
55	            return TypeName(name: "Bool")
56	        } else if Int(string) != nil {
57	            return TypeName(name: "Int")
58	        } else if Double(string) != nil {
59	            return TypeName(name: "Double")
60	        } else if string.isValidTupleName() {
61	            //tuple
62	            let string = string.dropFirstAndLast()
63	            let elements = string.commaSeparated()
64	            
65	            var types = [TupleElement]()
66	            var keys = [String?]()
67	            for (idx, element) in elements.enumerated() {
68	                let nameAndValue = element.colonSeparated()
69	                if nameAndValue.count == 1 {
70	                    guard let type = element.inferType else { return nil }
71	                    keys.append(nil)
72	                    types.append(TupleElement(name: "\(idx)", typeName: type))
73	                } else {
74	                    guard let type = nameAndValue[1].inferElementType else { return nil }
75	                    let name = nameAndValue[0]
76	                        .replacingOccurrences(of: "_", with: "")
77	                        .trimmingCharacters(in: .whitespaces)
78	                    if name.isEmpty {
79	                        keys.append(nil)
80	                        types.append(TupleElement(name: "\(idx)", typeName: type))
81	                    } else {
82	                        keys.append(name)
83	                        types.append(TupleElement(name: name, typeName: type))
84	                    }
85	                }
86	            }
87	            let body = zip(keys, types).map { key, element in
88	                if let key = key {
89	                    return "\(key): \(element.typeName.asSource)"
90	                } else {
91	                    return element.typeName.asSource
92	                }
93	            }.joined(separator: ", ")
94	            let name = "(\(body))"
95	            
96	            let tuple = TupleType(name: name, elements: types)
97	            return TypeName(name: name, tuple: tuple)
98	        } else if string.first == "[", string.last == "]" {
99	            //collection
100	            let string = string.dropFirstAndLast()
101	            let items = string
102	                .commaSeparated()
103	                .map {
104	                    $0
105	                        .trimmingCharacters(in: .whitespacesAndNewlines)
106	                        .strippingComments()
107	                        .trimmingCharacters(in: .whitespacesAndNewlines)
108	                }
109	            
110	            func genericType(from itemsTypes: [TypeName]) -> TypeName {
111	                var unique = Set(itemsTypes)
112	                
113	                if unique.count == 1, let type = unique.first {
114	                    return type
115	                } else if unique.count == 2, unique.remove(Self.optionalTypeName) != nil, let type = unique.first {
116	                    return TypeName(name: type.name,
117	                                    isOptional: true,
118	                                    isImplicitlyUnwrappedOptional: false,
119	                                    tuple: type.tuple,
120	                                    array: type.array,
121	                                    dictionary: type.dictionary,
122	                                    closure: type.closure,
123	                                    set: type.set,
124	                                    generic: type.generic
125	                    )
126	                }
127	                
128	                return TypeName(name: "Any")
129	            }
130	            
131	            if items[0].colonSeparated().count == 1 {
132	                var itemsTypes = [TypeName]()
133	                for item in items {
134	                    guard let type = item.inferElementType else {
135	                        return nil
136	                    }
137	                    itemsTypes.append(type)
138	                }
139	                let elementType = genericType(from: itemsTypes)
140	                let arrayType = ArrayType(name: "[\(elementType.asSource)]", elementTypeName: elementType)
141	                return TypeName(name: arrayType.name, array: arrayType, generic: arrayType.asGeneric)
142	            } else {
143	                var keysTypes = [TypeName]()
144	                var valuesTypes = [TypeName]()
145	                for items in items {
146	                    let keyAndValue = items.colonSeparated()
147	                    guard keyAndValue.count == 2,
148	                          let keyType = keyAndValue[0].inferElementType,
149	                          let valueType = keyAndValue[1].inferElementType
150	                    else {
151	                        return nil
152	                    }
153	                    
154	                    keysTypes.append(keyType)
155	                    valuesTypes.append(valueType)
156	                }
157	                let keyType = genericType(from: keysTypes)
158	                let valueType = genericType(from: valuesTypes)
159	                
160	                let dictionaryType = DictionaryType(name: "[\(keyType.asSource): \(valueType.asSource)]", valueTypeName: valueType, keyTypeName: keyType)
161	                return TypeName(name: dictionaryType.name, dictionary: dictionaryType, generic: dictionaryType.asGeneric)
162	            }
163	        } else if let generic = string.genericType() {
164	            return TypeName(name: generic.asSource, generic: generic)
165	        } else {
166	            // Enums, i.e. `Optional.some(...)` or `Optional.none` should be inferred to `Optional`
167	            // Contained types, i.e. `Foo.Bar()` should be inferred to `Foo.Bar`
168	            // This also supports initializers i.e. `MyType.SubType.init()`
169	            // But rarely enum cases can also start with capital letters, so we still may wrongly infer them as a type
170	            func possibleEnumType(_ string: String) -> String? {
171	                let components = string.components(separatedBy: ".", excludingDelimiterBetween: ("<[(", ")]>"))
172	                if components.count > 1, let lastComponentFirstLetter = components.last?.first.map(String.init) {
173	                    if lastComponentFirstLetter.lowercased() == lastComponentFirstLetter {
174	                        return components
175	                            .dropLast()
176	                            .joined(separator: ".")
177	                    }
178	                }
179	                return nil
180	            }
181	            
182	            // get everything before `(`
183	            let components = string.components(separatedBy: "(", excludingDelimiterBetween: ("<[(", ")]>"))
184	            
185	            // scenario for '}' is for property setter / getter logic
186	            // scenario for ! is for unwrapped optional
187	            let unwrappedOptional = string.last == "!"
188	            if components.count > 1 && (string.last == ")" || string.last == "}" || unwrappedOptional) {
189	                //initializer without `init`
190	                inferredType = components[0]
191	                let name = possibleEnumType(inferredType) ?? inferredType
192	                return name.inferType ?? TypeName(name + (unwrappedOptional ? "!" : ""))
193	            } else {
194	                return possibleEnumType(string).map { TypeName($0) }
195	            }
196	        }
197	    }
198	    
199	    func strippingComments() -> String {
200	        var finished: Bool
201	        var stripped = self
202	        repeat {
203	            finished = true
204	            let lines = StringView(stripped).lines
205	            if lines.count > 1 {
206	                stripped = lines.lazy
207	                    .filter({ line in !line.content.hasPrefix("//") })
208	                    .map(\.content)
209	                    .joined(separator: "\n")
210	            }
211	            if let annotationStart = stripped.range(of: "/*")?.lowerBound, let annotationEnd = stripped.range(of: "*/")?.upperBound {
212	                stripped = stripped.replacingCharacters(in: annotationStart ..< annotationEnd, with: "")
213	                    .trimmingCharacters(in: .whitespacesAndNewlines)
214	                finished = false
215	            }
216	        } while !finished
217	        
218	        return stripped
219	    }
220	    
221	    func strippingDefaultValues() -> String {
222	        if let defaultValueRange = self.range(of: "=") {
223	            return String(self[self.startIndex ..< defaultValueRange.lowerBound]).trimmingCharacters(in: .whitespaces)
224	        } else {
225	            return self
226	        }
227	    }
228	    
229	    fileprivate func genericType() -> GenericType? {
230	        var trimmed = self.trimmed
231	        
232	        guard let initializerCall = trimmed.lastIndex(of: "(") else {
233	            return nil
234	        }
235	        
236	        trimmed = String(trimmed[..<initializerCall])
237	        trimmed.trimSuffix(".init")
238	        
239	        guard let start = trimmed.firstIndex(of: "<"),
240	              trimmed.last == ">",
241	              start > trimmed.startIndex else {
242	            return nil
243	        }
244	        
245	        let body = trimmed[trimmed.index(after: start)..<trimmed.index(before: trimmed.endIndex)]
246	        return GenericType(name: String(trimmed[..<start]), typeParameters: String(body).commaSeparated().map({ value in
247	            let stripped = value.stripped()
248	            return GenericTypeParameter(typeName: stripped.inferType ?? TypeName(stripped))
249	        }))
250	    }
251	}
