3	public extension TriviaPiece {
4	    /// Returns string value of a comment piece or nil otherwise
5	    var comment: String? {
6	        switch self {
7	        case .spaces,
8	             .tabs,
9	             .verticalTabs,
10	             .formfeeds,
11	             .newlines,
12	             .carriageReturns,
13	             .carriageReturnLineFeeds,
14	             .unexpectedText,
15	             .backslashes,
16	             .pounds:
17	            return nil
18	        case .lineComment(let comment),
19	             .blockComment(let comment),
20	             .docLineComment(let comment),
21	             .docBlockComment(let comment):
22	            return comment
23	        }
24	    }
25	}
