10	public extension String {
11	
12	    /// Returns nil if string is empty
13	    var nilIfEmpty: String? {
14	        if isEmpty {
15	            return nil
16	        }
17	
18	        return self
19	    }
20	
21	    /// Returns nil if string is empty or contains `_` character
22	    var nilIfNotValidParameterName: String? {
23	        if isEmpty {
24	            return nil
25	        }
26	
27	        if self == "_" {
28	            return nil
29	        }
30	
31	        return self
32	    }
33	
34	    /// :nodoc:
35	    /// - Parameter substring: Instance of a substring
36	    /// - Returns: Returns number of times a substring appears in self
37	    func countInstances(of substring: String) -> Int {
38	        guard !substring.isEmpty else { return 0 }
39	        var count = 0
40	        var searchRange: Range<String.Index>?
41	        while let foundRange = range(of: substring, options: [], range: searchRange) {
42	            count += 1
43	            searchRange = Range(uncheckedBounds: (lower: foundRange.upperBound, upper: endIndex))
44	        }
45	        return count
46	    }
47	
48	    /// :nodoc:
49	    /// Removes leading and trailing whitespace from str. Returns false if str was not altered.
50	    @discardableResult
51	    mutating func strip() -> Bool {
52	        let strippedString = stripped()
53	        guard strippedString != self else { return false }
54	        self = strippedString
55	        return true
56	    }
57	
58	    /// :nodoc:
59	    /// Returns a copy of str with leading and trailing whitespace removed.
60	    func stripped() -> String {
61	        return String(self.trimmingCharacters(in: .whitespaces))
62	    }
63	
64	    /// :nodoc:
65	    @discardableResult
66	    mutating func trimPrefix(_ prefix: String) -> Bool {
67	        guard hasPrefix(prefix) else { return false }
68	        self = String(self.suffix(self.count - prefix.count))
69	        return true
70	    }
71	
72	    /// :nodoc:
73	    func trimmingPrefix(_ prefix: String) -> String {
74	        guard hasPrefix(prefix) else { return self }
75	        return String(self.suffix(self.count - prefix.count))
76	    }
77	
78	    /// :nodoc:
79	    @discardableResult
80	    mutating func trimSuffix(_ suffix: String) -> Bool {
81	        guard hasSuffix(suffix) else { return false }
82	        self = String(self.prefix(self.count - suffix.count))
83	        return true
84	    }
85	
86	    /// :nodoc:
87	    func trimmingSuffix(_ suffix: String) -> String {
88	        guard hasSuffix(suffix) else { return self }
89	        return String(self.prefix(self.count - suffix.count))
90	    }
91	
92	    /// :nodoc:
93	    func dropFirstAndLast(_ n: Int = 1) -> String {
94	        return drop(first: n, last: n)
95	    }
96	
97	    /// :nodoc:
98	    func drop(first: Int, last: Int) -> String {
99	        return String(self.dropFirst(first).dropLast(last))
100	    }
101	
102	    /// :nodoc:
103	    /// Wraps brackets if needed to make a valid type name
104	    func bracketsBalancing() -> String {
105	        if hasPrefix("(") && hasSuffix(")") {
106	            let unwrapped = dropFirstAndLast()
107	            return unwrapped.commaSeparated().count == 1 ? unwrapped.bracketsBalancing() : self
108	        } else {
