114	    /// :nodoc:
115	    /// Returns true if given string can represent a valid tuple type name
116	    func isValidTupleName() -> Bool {
117	        guard hasPrefix("(") && hasSuffix(")") else { return false }
118	        let trimmedBracketsName = dropFirstAndLast()
119	        return trimmedBracketsName.isBracketsBalanced() && trimmedBracketsName.commaSeparated().count > 1
120	    }
121	
122	    /// :nodoc:
123	    func isValidArrayName() -> Bool {
124	        if hasPrefix("Array<") { return true }
125	        if hasPrefix("[") && hasSuffix("]") {
126	            return dropFirstAndLast().colonSeparated().count == 1
127	        }
128	        return false
129	    }
130	
131	    /// :nodoc:
132	    func isValidDictionaryName() -> Bool {
133	        if hasPrefix("Dictionary<") { return true }
134	        if hasPrefix("[") && contains(":") && hasSuffix("]") {
135	            return dropFirstAndLast().colonSeparated().count == 2
136	        }
137	        return false
138	    }
