140	    /// :nodoc:
141	    func isValidClosureName() -> Bool {
142	        return components(separatedBy: "->", excludingDelimiterBetween: (["(", "<"], [")", ">"])).count > 1
143	    }
144	
145	    /// :nodoc:
146	    /// Returns true if all opening brackets are balanced with closed brackets.
147	    func isBracketsBalanced() -> Bool {
148	        var bracketsCount: Int = 0
149	        for char in self {
150	            if char == "(" { bracketsCount += 1 } else if char == ")" { bracketsCount -= 1 }
151	            if bracketsCount < 0 { return false }
152	        }
153	        return bracketsCount == 0
154	    }
