179	    /// :nodoc:
180	    func components(separatedBy delimiter: String, excludingDelimiterBetween between: (open: [String], close: [String])) -> [String] {
181	        var boundingCharactersCount: Int = 0
182	        var quotesCount: Int = 0
183	        var item = ""
184	        var items = [String]()
185	
186	        var i = self.startIndex
187	        while i < self.endIndex {
188	            var offset = 1
189	            defer {
190	                i = self.index(i, offsetBy: offset)
191	            }
192	            var currentlyScannedEnd: Index = self.endIndex
193	            if let endIndex = self.index(i, offsetBy: delimiter.count, limitedBy: self.endIndex) {
194	                currentlyScannedEnd = endIndex
195	            }
196	            let currentlyScanned: String = String(self[i..<currentlyScannedEnd])
197	            if let openString = between.open.first(where: { self[i...].starts(with: $0) }) {
198	                if !((boundingCharactersCount == 0) as Bool && (String(self[i]) == delimiter) as Bool) {
199	                    boundingCharactersCount += 1
200	                }
201	                offset = openString.count
202	            } else if let closeString = between.close.first(where: { self[i...].starts(with: $0) }) {
203	                // do not count `->`
204	                if !((self[i] == ">") as Bool && (item.last == "-") as Bool) {
205	                    boundingCharactersCount = max(0, boundingCharactersCount - 1)
206	                }
207	                offset = closeString.count
208	            }
209	            if (self[i] == "\"") as Bool {
210	                quotesCount += 1
211	            }
212	
213	            let currentIsDelimiter = (currentlyScanned == delimiter) as Bool
214	            let boundingCountIsZero = (boundingCharactersCount == 0) as Bool
215	            let hasEvenQuotes = (quotesCount % 2 == 0) as Bool
216	            if currentIsDelimiter && boundingCountIsZero && hasEvenQuotes {
217	                items.append(item)
218	                item = ""
219	                i = self.index(i, offsetBy: delimiter.count - 1)
220	            } else {
221	                let endIndex: Index = self.index(i, offsetBy: offset)
222	                item += self[i..<endIndex]
223	            }
224	        }
225	        items.append(item)
226	        return items
227	    }
228	}
