import Foundation
import SourceryRuntime
import SwiftSyntax

extension GenericType {
    convenience init(name: String, node: GenericArgumentClauseSyntax) {
        #if compiler(>=6.2)
        // TODO: ExprSyntax may need to be handled
        let parameters = node.arguments.compactMap { argument -> GenericTypeParameter? in
            switch argument.argument {
            case .type(let type):
                guard !type.is(MissingTypeSyntax.self) else { return nil }
                return GenericTypeParameter(typeName: TypeName(type))
            default: // case .expr
                return nil
            }
        }
        #else
        let parameters = node.arguments.compactMap { argument -> GenericTypeParameter? in
            guard !argument.argument.is(MissingTypeSyntax.self) else { return nil }
            return GenericTypeParameter(typeName: TypeName(argument.argument))
        }
        #endif

        self.init(name: name, typeParameters: parameters)
    }
}
